def _aggregate(self):
    """Sum all entries converted to base currency using Decimal arithmetic
    to avoid floating-point accumulation drift."""
    total = Decimal("0")
    for entry in self.entries:
        amount = Decimal(str(entry["amount"]))
        if entry["currency"] == self.base:
            total += amount
        else:
            rate = RATES.get((entry["currency"], self.base))
            if rate is None:
                raise ValueError(f"No rate for {entry['currency']}->{self.base}")
            total += amount * Decimal(str(rate))
    return float(total)

